//
// The gateway is the single MCP server that an agent host (Claude Code, etc.)
// connects to. It aggregates tools from downstream MCP servers, re-exposes
// them under namespaced names, and intercepts every tools/call for governance.
//
// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
//
// Modes:
//   - Embedded (default): runs an in-process Aileron server with in-memory stores.
//   - Remote: set AILERON_API_URL to connect to an existing Aileron server.
package main

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/ALRubinger/aileron/core/app"
	"github.com/ALRubinger/aileron/core/approval"
	"github.com/ALRubinger/aileron/core/config"
	"github.com/ALRubinger/aileron/core/policy"
	"github.com/ALRubinger/aileron/core/store/mem"
	"github.com/ALRubinger/aileron/core/vault"
	"github.com/ALRubinger/aileron/core/version"
	"github.com/google/uuid"
)

// --- JSON-RPC types ---

type jsonrpcRequest struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Method  string          `json:"method"`
	Params  json.RawMessage `json:"params,omitempty"`
}

type jsonrpcResponse struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Result  any             `json:"result,omitempty"`
	Error   *jsonrpcError   `json:"error,omitempty"`
}

type jsonrpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

// --- MCP types ---

type toolDef struct {
	Name        string `json:"name"`
	Description string `json:"description"`
	InputSchema schema `json:"inputSchema"`
}

type schema struct {
	Type       string                `json:"type"`
	Properties map[string]schemaProp `json:"properties,omitempty"`
	Required   []string              `json:"required,omitempty"`
}

type schemaProp struct {
	Type        string `json:"type"`
	Description string `json:"description"`
}

type callToolParams struct {
	Name      string         `json:"name"`
	Arguments map[string]any `json:"arguments"`
}

type toolResult struct {
	Content []toolContent `json:"content"`
	IsError bool          `json:"isError,omitempty"`
}

type toolContent struct {
	Type string `json:"type"`
	Text string `json:"text"`
}

// --- Server ---

type server struct {
	gw  *gateway
	log *slog.Logger
}

func main() {
	log := slog.New(slog.NewJSONHandler(os.Stderr, &slog.HandlerOptions{Level: slog.LevelInfo}))
	ctx := context.Background()

	// Start embedded Aileron server if no remote URL is configured.
	// This provides the control plane (policy engine, approval orchestrator, vault).
	var v vault.Vault
	apiURL := os.Getenv("AILERON_API_URL")
	if apiURL == "" {
		discardLog := slog.New(slog.NewJSONHandler(io.Discard, nil))
		handler, err := app.NewHandler(discardLog)
		if err != nil {
			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to start embedded server: %v\n", err)
			os.Exit(1)
		}
		listener, err := net.Listen("tcp", "127.0.0.1:0")
		if err != nil {
			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to listen: %v\n", err)
			os.Exit(1)
		}
		go http.Serve(listener, handler)
		apiURL = "http://" + listener.Addr().String()

		// In embedded mode, create an in-memory vault for credential injection.
		v = vault.NewMemVault()
	}

	// Load gateway configuration.
	cfg, err := config.LoadFromEnvOrDefault()
	if err != nil {
		fmt.Fprintf(os.Stderr, "aileron-mcp: failed to load config: %v\n", err)
		os.Exit(1)
	}

	// Build policy engine with seeded policies.
	policyStore := mem.NewPolicyStore()
	if err := policy.SeedPolicies(ctx, policyStore); err != nil {
		fmt.Fprintf(os.Stderr, "aileron-mcp: failed to seed policies: %v\n", err)
		os.Exit(1)
	}
	policyEngine := policy.NewRuleEngine(policyStore)

	// Build approval orchestrator.
	approvalStore := mem.NewApprovalStore()
	idGen := func() string { return uuid.New().String() }
	orchestrator := approval.NewInMemoryOrchestrator(approvalStore, idGen)

	// Build in-memory audit store.
	auditStore := newMemAuditStore()

	// Connect to downstream MCP servers.
	gw, err := newGateway(ctx, gatewayConfig{
		Cfg:          cfg,
		APIURL:       apiURL,
		Vault:        v,
		PolicyEngine: policyEngine,
		Approvals:    orchestrator,
		AuditStore:   auditStore,
		Log:          log,
	})
	if err != nil {
		fmt.Fprintf(os.Stderr, "aileron-mcp: failed to start gateway: %v\n", err)
		os.Exit(1)
	}

	// Handle SIGTERM and SIGINT for graceful shutdown.
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGTERM, syscall.SIGINT)
	go func() {
		sig := <-sigCh
		log.Info("received signal, shutting down", "signal", sig.String())
		shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer cancel()
		gw.Shutdown(shutdownCtx)
		os.Exit(0)
	}()
	defer gw.closeAll()

	s := &server{gw: gw, log: log}

	scanner := bufio.NewScanner(os.Stdin)
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)

	for scanner.Scan() {
		line := scanner.Bytes()
		if len(line) == 0 {
			continue
		}

		var req jsonrpcRequest
		if err := json.Unmarshal(line, &req); err != nil {
			continue
		}

		resp := s.handle(req)
		if resp != nil {
			data, _ := json.Marshal(resp)
			fmt.Fprintf(os.Stdout, "%s\n", data)
		}
	}
}

func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
	switch req.Method {
	case "initialize":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result: map[string]any{
				"protocolVersion": "2024-11-05",
				"capabilities": map[string]any{
					"tools": map[string]any{},
				},
				"serverInfo": map[string]any{
					"name":    "aileron",
					"version": "0.0.2",
				},
			},
		}

	case "notifications/initialized":
		return nil // no response for notifications

	case "tools/list":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result: map[string]any{
				"tools": s.gw.aggregatedTools(),
			},
		}

	case "tools/call":
		var params callToolParams
		if err := json.Unmarshal(req.Params, &params); err != nil {
			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
		}
		ctx := context.Background()
		result := s.gw.routeToolCall(ctx, params.Name, params.Arguments)
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result:  result,
		}

	case "ping":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result:  map[string]any{},
		}

	default:
		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
	}
}

// --- Helpers ---

func argStr(args map[string]any, key string) string {
	v, ok := args[key]
	if !ok {
		return ""
	}
	s, ok := v.(string)
	if !ok {
		return ""
	}
	return s
}

func jsonResult(v any) toolResult {
	data, _ := json.MarshalIndent(v, "", "  ")
	return toolResult{
		Content: []toolContent{{Type: "text", Text: string(data)}},
	}
}

func errorResult(msg string) toolResult {
	return toolResult{
		Content: []toolContent{{Type: "text", Text: msg}},
		IsError: true,
	}
}

func errorResponse(id json.RawMessage, code int, msg string) *jsonrpcResponse {
	return &jsonrpcResponse{
		JSONRPC: "2.0",
		ID:      id,
		Error:   &jsonrpcError{Code: code, Message: msg},
	}
}

// Package mcpclient provides a Go client that speaks Model Context Protocol (MCP)
// over stdio to downstream MCP servers running as subprocesses.
//
// Communication uses newline-delimited JSON-RPC 2.0 over the subprocess's
// stdin (requests) and stdout (responses).
package mcpclient

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"os/exec"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	"github.com/ALRubinger/aileron/core/mcp"
)

// Client manages a connection to a single downstream MCP server subprocess.
type Client struct {
	name   string
	cmd    *exec.Cmd
	stdin  io.WriteCloser
	stdout *bufio.Reader
	mu     sync.Mutex // protects writes to stdin and reads from stdout
	tools  []mcp.ToolDef
	nextID int64
}

// JSON-RPC 2.0 wire types (internal).

type jsonrpcRequest struct {
	JSONRPC string `json:"jsonrpc"`
	ID      any    `json:"id,omitempty"`
	Method  string `json:"method"`
	Params  any    `json:"params,omitempty"`
}

type jsonrpcResponse struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Result  json.RawMessage `json:"result,omitempty"`
	Error   *jsonrpcError   `json:"error,omitempty"`
}

type jsonrpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

func (e *jsonrpcError) Error() string {
	return fmt.Sprintf("jsonrpc error %d: %s", e.Code, e.Message)
}

// NewClient spawns a downstream MCP server as a subprocess and performs the
// MCP initialize handshake. The command slice must contain at least the
// program name; additional elements are passed as arguments. The env slice
// is merged with os.Environ() so the subprocess inherits the current
// environment plus any overrides.
func NewClient(ctx context.Context, name string, command []string, env []string) (*Client, error) {
	if len(command) == 0 {
		return nil, fmt.Errorf("mcpclient: command must not be empty")
	}

	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
	cmd.Env = append(os.Environ(), env...)
	cmd.Stderr = os.Stderr

	stdinPipe, err := cmd.StdinPipe()
	if err != nil {
		return nil, fmt.Errorf("mcpclient: stdin pipe: %w", err)
	}

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return nil, fmt.Errorf("mcpclient: stdout pipe: %w", err)
	}

	if err := cmd.Start(); err != nil {
		return nil, fmt.Errorf("mcpclient: start %q: %w", command[0], err)
	}

	c := &Client{
		name:   name,
		cmd:    cmd,
		stdin:  stdinPipe,
		stdout: bufio.NewReader(stdoutPipe),
		nextID: 1, // 1 is reserved for the initialize request
	}

	// --- MCP initialize handshake ---

	initParams := map[string]any{
		"protocolVersion": "2024-11-05",
		"capabilities":    map[string]any{},
		"clientInfo": map[string]any{
			"name":    "aileron-gateway",
			"version": "0.0.1",
		},
	}

	_, err = c.sendRequest("initialize", initParams)
	if err != nil {
		// Best-effort cleanup on failure.
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: initialize handshake: %w", err)
	}

	// Send the initialized notification (no ID — it's a notification).
	if err := c.sendNotification("notifications/initialized"); err != nil {
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: initialized notification: %w", err)
	}

	// Discover available tools.
	if _, err := c.DiscoverTools(ctx); err != nil {
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: discover tools: %w", err)
	}

	return c, nil
}

// DiscoverTools sends a tools/list request and caches the result.
func (c *Client) DiscoverTools(_ context.Context) ([]mcp.ToolDef, error) {
	raw, err := c.sendRequest("tools/list", nil)
	if err != nil {
		return nil, err
	}

	var envelope struct {
		Tools []mcp.ToolDef `json:"tools"`
	}
	if err := json.Unmarshal(raw, &envelope); err != nil {
		return nil, fmt.Errorf("mcpclient: parse tools/list result: %w", err)
	}

	c.tools = envelope.Tools
	return c.tools, nil
}

// CallTool invokes a tool on the downstream MCP server by name.
func (c *Client) CallTool(_ context.Context, name string, arguments map[string]any) (*mcp.ToolResult, error) {
	params := map[string]any{
		"name":      name,
		"arguments": arguments,
	}

	raw, err := c.sendRequest("tools/call", params)
	if err != nil {
		return nil, err
	}

	var result mcp.ToolResult
	if err := json.Unmarshal(raw, &result); err != nil {
		return nil, fmt.Errorf("mcpclient: parse tools/call result: %w", err)
	}

	return &result, nil
}

// Tools returns the cached list of tools discovered from the server.
func (c *Client) Tools() []mcp.ToolDef {
	return c.tools
}

// Name returns the human-readable name of this client connection.
func (c *Client) Name() string {
	return c.name
}

// Close terminates the subprocess. It sends SIGTERM first, then SIGKILL
// after a 5-second timeout if the process hasn't exited.
func (c *Client) Close() error {
	if c.cmd == nil || c.cmd.Process == nil {
		return nil
	}

	// Close stdin so the subprocess sees EOF.
	_ = c.stdin.Close()

	// Send SIGTERM.
	if err := c.cmd.Process.Signal(syscall.SIGTERM); err != nil {
		// Process may have already exited; just wait.
		_ = c.cmd.Wait()
		return nil
	}

	// Wait up to 5 seconds for graceful exit.
	done := make(chan error, 1)
	go func() {
		done <- c.cmd.Wait()
	}()

	select {
	case err := <-done:
		return err
	case <-time.After(5 * time.Second):
		_ = c.cmd.Process.Kill()
		return <-done
	}
}

// nextRequestID returns a monotonically increasing request ID.
func (c *Client) nextRequestID() int64 {
	return atomic.AddInt64(&c.nextID, 1)
}

// sendRequest sends a JSON-RPC request and waits for the corresponding
// response. It returns the raw "result" field on success.
func (c *Client) sendRequest(method string, params any) (json.RawMessage, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	id := c.nextRequestID()
	req := jsonrpcRequest{
		JSONRPC: "2.0",
		ID:      id,
		Method:  method,
		Params:  params,
	}

	data, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("mcpclient: marshal request: %w", err)
	}

	// Write newline-delimited JSON.
	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
		return nil, fmt.Errorf("mcpclient: write request: %w", err)
	}

	resp, err := c.readResponse()
	if err != nil {
		return nil, err
	}

	if resp.Error != nil {
		return nil, resp.Error
	}

	return resp.Result, nil
}

// sendNotification sends a JSON-RPC notification (no ID, no response expected).
func (c *Client) sendNotification(method string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	req := jsonrpcRequest{
		JSONRPC: "2.0",
		Method:  method,
	}

	data, err := json.Marshal(req)
	if err != nil {
		return fmt.Errorf("mcpclient: marshal notification: %w", err)
	}

	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
		return fmt.Errorf("mcpclient: write notification: %w", err)
	}

	return nil
}

// readResponse reads one newline-delimited JSON line from the subprocess
// stdout and parses it as a JSON-RPC response.
func (c *Client) readResponse() (*jsonrpcResponse, error) {
	line, err := c.stdout.ReadBytes('\n')
	if err != nil {
		return nil, fmt.Errorf("mcpclient: read response: %w", err)
	}

	var resp jsonrpcResponse
	if err := json.Unmarshal(line, &resp); err != nil {
		return nil, fmt.Errorf("mcpclient: parse response: %w (raw: %s)", err, string(line))
	}

	return &resp, nil
}

